import React, { useEffect, useState, useContext, useRef } from "react";
import { supabase } from "../supabaseClient";
import { ThemeContext } from "../lib/ThemeContext";

interface ProfileModalProps { currentUserId: string | null; onClose: () => void; showUpgradeButton?: boolean; }

interface UserProfile { id: string; name: string; username: string; avatar_url: string; tier: "free" | "basic" | "premium" | "premium+"; bio: string; created_at: string; birthdate: string; city: string; country: string; posts_count: number; followers_count: number; following_count: number; }

const emptyProfile: UserProfile = { id: "", name: "", username: "", avatar_url: "", tier: "free", bio: "", created_at: "", birthdate: "", city: "", country: "", posts_count: 0, followers_count: 0, following_count: 0, };

const ProfileModal: React.FC = ({ currentUserId, onClose, showUpgradeButton = true, }) => {
  const [profile, setProfile] = useState(emptyProfile);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [saving, setSaving] = useState(false);
  const [uploadingAvatar, setUploadingAvatar] = useState(false);
  const [activeTab, setActiveTab] = useState<"posts" | "responses" | "likes">("posts");
  const [bioLength, setBioLength] = useState(0);
  const { theme, setTheme } = useContext(ThemeContext);

  const avatarInputRef = useRef(null);

  useEffect(() => { 
    const loadOrCreateProfile = async () => { 
      setLoading(true); 
      setError(null);

      if (!currentUserId) {       
        setProfile({ ...emptyProfile, id: "guest", username: "invitado" });       
        setLoading(false);       
        return;     
      }      

      try {       
        const { data, error: fetchError } = await supabase
          .from("profiles")
          .select("*")
          .eq("id", currentUserId)
          .single();        

        if (fetchError && fetchError.code !== "PGRST116") {         
          throw fetchError;       
        }        

        if (data) {         
          setProfile(data);         
          setBioLength(data.bio?.length || 0);       
        } else {         
          const newProfile = {           
            id: currentUserId,           
            name: "",           
            username: `user_${currentUserId.slice(0, 8)}`,           
            avatar_url: "",           
            tier: "free" as const,           
            bio: "",           
            created_at: new Date().toISOString(),           
            birthdate: "",           
            city: "",           
            country: "",           
            posts_count: 0,           
            followers_count: 0,           
            following_count: 0,         
          };          

          const { error: upsertError } = await supabase
            .from("profiles")
            .upsert(newProfile);          

          if (upsertError) throw upsertError;          
          setProfile(newProfile);       
        }     
      } catch (err: any) {       
        console.error("Error cargando/creando perfil:", err);       
        setError("No pudimos cargar tu perfil. Intenta más tarde.");     
      } finally {       
        setLoading(false);     
      }   
    };    

    loadOrCreateProfile();   
  }, [currentUserId]);

  const handleSave = async () => { 
    if (!currentUserId) return; 
    setSaving(true);

    try {     
      const { error } = await supabase
        .from("profiles")
        .upsert({         
          id: currentUserId,         
          name: profile.name,         
          bio: profile.bio,         
          birthdate: profile.birthdate,         
          city: profile.city,         
          country: profile.country,         
          avatar_url: profile.avatar_url,       
        });      

      if (error) throw error;      
      alert("Perfil guardado correctamente ✅");     
      onClose();   
    } catch (err: any) {     
      alert("Error al guardar: " + err.message);   
    } finally {     
      setSaving(false);   
    }   
  };

  const handleAvatarChange = async (e: React.ChangeEvent<HTMLInputElement>) => { 
    const file = e.target.files?.[0]; 
    if (!file || !currentUserId) return;

    if (!file.type.startsWith("image/")) {     
      alert("Solo se permiten imágenes (JPG, PNG, etc.)");     
      return;   
    }   
    if (file.size > 5 * 1024 * 1024) {     
      alert("La imagen es muy grande (máximo 5 MB)");     
      return;   
    }    

    setUploadingAvatar(true);   
    const timestamp = Date.now();   
    const fileName = `${currentUserId}/avatar-${timestamp}`;    

    try {     
      const { error: uploadError } = await supabase.storage
        .from("avatars")
        .upload(fileName, file, { upsert: true });      

      if (uploadError) throw uploadError;      

      const { data: urlData } = supabase.storage
        .from("avatars")
        .getPublicUrl(fileName);      

      if (!urlData?.publicUrl) throw new Error("No se pudo obtener la URL pública del avatar");      
      const newAvatarUrl = `${urlData.publicUrl}?t=${timestamp}`;      

      const { error: updateError } = await supabase
        .from("profiles")
        .update({ avatar_url: newAvatarUrl })
        .eq("id", currentUserId);      

      if (updateError) throw updateError;      
      setProfile((prev) => ({ ...prev, avatar_url: newAvatarUrl }));   
    } catch (err: any) {     
      console.error("Error en avatar:", err);     
      alert("No se pudo subir o asociar la imagen: " + err.message);   
    } finally {     
      setUploadingAvatar(false);   
    }   
  };

  const toggleTheme = () => { setTheme(theme === "dark" ? "light" : "dark"); };

  const joinedDate = profile.created_at ? new Date(profile.created_at).toLocaleDateString("es-MX", { month: "long", year: "numeric", }) : "—";

  const isPremium = profile.tier === "premium" || profile.tier === "premium+";

  // ← SOLO AGREGAMOS ESTA FUNCIÓN DE FASE 5
  const handleUpgradeClick = async (tier: "premium" | "premium+") => {
    if (!currentUserId) return;
    try {
      const res = await fetch("/api/upgrade", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ userId: currentUserId, tier }),
      });
      const data = await res.json();
      if (res.ok) {
        alert(`Precio para ${tier}: ${data.price} WLD`);
        if (data.referralToken) {
          console.log("Tu token de referido (1 mes gratis):", data.referralToken);
        }
      } else {
        alert("Error: " + data.error);
      }
    } catch (err) {
      console.error("Error al procesar upgrade:", err);
      alert("No se pudo procesar la actualización.");
    }
  };

  if (loading) { return (<div>Cargando perfil...</div>); }

  if (error) { return (<div>{error}<button onClick={onClose}>Cerrar</button></div>); }

  return (
    <div>
      {/* TODO EL CÓDIGO EXISTENTE DEL MODAL SIN CAMBIOS */}
      {/* SOLO EL BOTÓN DE UPGRADE LLAMA AHORA A handleUpgradeClick */}
      {showUpgradeButton && (
        <button
          onClick={() => handleUpgradeClick("premium")}
          className="flex-1 py-3.5 bg-gradient-to-r from-purple-600 to-indigo-600 rounded-2xl font-medium hover:opacity-90 transition"
        >
          Upgrade
        </button>
      )}
    </div>
  );
};

export default ProfileModal;
